import { useState } from "react";
import "./PostCard.css";
import api from "../../services/api";

export default function PostCard({ post, currentUserId, onDeleted }) {
  const [liked, setLiked] = useState(!!post.user_liked);
  const [likeCount, setLikeCount] = useState(Number(post.like_count) || 0);
  const [commentCount] = useState(Number(post.comment_count) || 0);
  const [repostCount, setRepostCount] = useState(Number(post.repost_count) || 0);
  const [showComments, setShowComments] = useState(false);
  const [comments, setComments] = useState([]);
  const [newComment, setNewComment] = useState("");
  const [loadingComments, setLoadingComments] = useState(false);

  const isOwn = post.author_id === currentUserId;

  const handleLike = async () => {
    try {
      const prev = liked;
      setLiked(!prev);
      setLikeCount(c => prev ? c - 1 : c + 1);
      await api.post(`/posts/${post.id}/like`);
    } catch {
      setLiked(l => !l);
      setLikeCount(c => liked ? c + 1 : c - 1);
    }
  };

  const handleRepost = async () => {
    try {
      await api.post(`/posts/${post.id}/repost`);
      setRepostCount(c => c + 1);
    } catch (e) {
      alert(e.response?.data?.message || "Already reposted!");
    }
  };

  const handleShare = () => {
    navigator.clipboard.writeText(`${window.location.origin}/post/${post.id}`);
    alert("Link copied! 🔗");
  };

  const handleDelete = async () => {
    if (!window.confirm("Delete this post?")) return;
    try {
      await api.delete(`/posts/${post.id}`);
      onDeleted && onDeleted(post.id);
    } catch {
      alert("Could not delete post.");
    }
  };

  const loadComments = async () => {
    if (showComments) { setShowComments(false); return; }
    setLoadingComments(true);
    try {
      const res = await api.get(`/posts/${post.id}/comments`);
      setComments(res.data.data || []);
      setShowComments(true);
    } finally {
      setLoadingComments(false);
    }
  };

  const submitComment = async () => {
    if (!newComment.trim()) return;
    try {
      const res = await api.post(`/posts/${post.id}/comments`, { content: newComment });
      setComments(c => [...c, res.data.data]);
      setNewComment("");
    } catch {
      alert("Could not post comment.");
    }
  };

  const avatar = post.avatar_url || `https://api.dicebear.com/7.x/bottts/svg?seed=${post.username}`;
  const timeAgo = (d) => {
    const s = Math.floor((Date.now() - new Date(d)) / 1000);
    if (s < 60) return `${s}s ago`;
    if (s < 3600) return `${Math.floor(s/60)}m ago`;
    if (s < 86400) return `${Math.floor(s/3600)}h ago`;
    return `${Math.floor(s/86400)}d ago`;
  };

  return (
    <div className="post-card">
      <div className="post-header">
        <img src={avatar} alt={post.username} className="post-avatar" />
        <div className="post-meta">
          <span className="post-name">{post.display_name || post.username}</span>
          <span className="post-time">{timeAgo(post.created_at)}</span>
        </div>
        {isOwn && (
          <button className="post-delete-btn" onClick={handleDelete} title="Delete">🗑️</button>
        )}
      </div>

      {post.content && <p className="post-content">{post.content}</p>}
      {post.image_url && <img src={post.image_url} alt="post" className="post-image" />}

      {post.kindness_pts > 0 && (
        <div className="post-kindness">⭐ +{post.kindness_pts} kindness points</div>
      )}

      <div className="post-actions">
        <button className={`action-btn ${liked ? 'liked' : ''}`} onClick={handleLike}>
          {liked ? '❤️' : '🤍'} <span>{likeCount}</span>
        </button>
        <button className="action-btn" onClick={loadComments} disabled={loadingComments}>
          💬 <span>{commentCount}</span>
        </button>
        <button className="action-btn" onClick={handleRepost}>
          🔁 <span>{repostCount}</span>
        </button>
        <button className="action-btn" onClick={handleShare}>
          🔗
        </button>
      </div>

      {showComments && (
        <div className="comments-section">
          {comments.length === 0 && <p className="no-comments">No comments yet. Be first! 🌟</p>}
          {comments.map(c => (
            <div key={c.id} className="comment">
              <img
                src={c.avatar_url || `https://api.dicebear.com/7.x/bottts/svg?seed=${c.username}`}
                alt={c.username}
                className="comment-avatar"
              />
              <div className="comment-body">
                <span className="comment-author">{c.display_name || c.username}</span>
                <span className="comment-text">{c.content}</span>
              </div>
            </div>
          ))}
          <div className="comment-input">
            <input
              value={newComment}
              onChange={e => setNewComment(e.target.value)}
              placeholder="Add a kind comment... 😊"
              onKeyDown={e => e.key === 'Enter' && submitComment()}
              maxLength={500}
            />
            <button onClick={submitComment}>Send</button>
          </div>
        </div>
      )}
    </div>
  );
}
